var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"으음…","JPN":"んん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"하아, 이제야 일어났네.","JPN":"はあ、やっと起きたのね。","ENG":"*Sigh* You're finally awake.","TWN":"哼，你現在才睡醒是吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"낭자…? 왜 그대가 내 앞자리에 있는 거요?","JPN":"貴殿……？　何ゆえ自分の前の席に……？","ENG":"You're, blonde maiden...? Why are you sitting in front of me?","TWN":"姑娘…？你為何要站在在下前面？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"\xA0그야 마지막 수업은 한참 전에 끝났으니까.","JPN":"\xA0今日の授業はもうとっくに終わったからよ。","ENG":"\xA0Because our last class ended ages ago.","TWN":"因為最後一堂課早就下課了，"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 오늘 교실 문단속은 나라구.","JPN":"そして、今日の教室の戸締り当番は私。","ENG":"Also, I'm supposed to lock up our classroom today.","TWN":"然後我今天是值日生負責鎖門。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"폐를 끼쳤구려.","JPN":"それは……ご迷惑をお掛けしました。","ENG":"I have caused you inconvenience.","TWN":"給你添麻煩了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼, 수업이 끝난 뒤에도 본인을 빤히 지켜 보기만 하던 거요?","JPN":"にしても、授業が終わってからずっと自分をじろじろと見ていたんですか？","ENG":"Then, have you been staring at me this whole time after class had ended?","TWN":"所以下課後你就一直凝視在下嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"누, 누가 빤히 지켜봤다는 거야?! 다른 사람이 들으면 오해할 소리 좀 하지 마!","JPN":"じ、じろじろって何！？　変な言い方はやめて！","ENG":"W-who said anything about staring?! Stop saying things that could give people the wrong idea!","TWN":"誰，誰凝視你啦？！少說這種別人聽到會誤會的話！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"깨웠는데 네가 안 일어난 거거든?!","JPN":"起こしても起きなかったのはあんたでしょう！？","ENG":"I tried to wake you up, but you wouldn't budge!","TWN":"我有叫你，是你沒起來好嗎！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 난 너 안 보고 폰으로 게임 하고 있었거든?! 신기록 경신이었거든?!","JPN":"それに、私はスマホゲームに熱中していたの！　新記録達成よ？","ENG":"Also, I wasn't just waiting on you! I was playing games on my phone! See? I even broke my previous high score!","TWN":"而且我才沒有在看你，我是在玩手遊，而且還創新紀錄咧！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…너 말이야. 진짜로 무슨 병이라도 있는 건 아니지?","JPN":"……あんたってさ。それ、なにかの病気じゃない？","ENG":"...I'm just asking, but... you're not sick, are you?","TWN":"…我問你，你該不會身體真的有什麼問題吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"낮에만 그렇게 자는 건 누가 봐도 이상하다고.","JPN":"昼の間、ぶっ通しで寝るなんて明らかにおかしいわよ。","ENG":"Because it's weird to see someone sleep all day like that.","TWN":"只有白天才睡得那麼熟，一定哪裡有問題吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"아마도 습관이 되었기 때문일 거요. 고향에서는 주로 밤에만 활동했으니.","JPN":"おそらく昔からの習慣のせいでしょう。故郷では夜が主な活動時間だったので。","ENG":"Most likely, it is out of habit. In my hometown, I primarily worked during the night.","TWN":"應該是習慣的關係，因為在老家時，主要的活動時間都是在晚上。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"하아? 대체 뭣 때문에 밤에 깨어 있는 건데?","JPN":"はあ？　どうして夜？","ENG":"Huh? What were you doing staying up all night?","TWN":"蛤？為什麼專挑晚上？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"악인들의 암약과 음모는 주로 밤에 일어나는 법이니, 본인 또한 그런 자들을 처단하기 위해…","JPN":"悪人たちは夜に暗躍し、黒い計画は夜実行されるもの、自分はそのようなものを始末するため……","ENG":"Malicious schemes and conspiracies are bound to happen at night. I was there to put an end to those people...","TWN":"因為壞人通常都在晚上犯罪，所以也只能在晚上處決他們…"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"처단…?","JPN":"始末……？","ENG":"Put an end...?","TWN":"處決…？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양. 잠시 면담이 필요할 것 같군요.","JPN":"シエルさん。少し面談をお願いしたいのですが。","ENG":"Ciel? May I have a word with you?","TWN":"希爾同學，我有事找你。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"에엑? 학생회장?! 이 타이밍에?!","JPN":"ええっ？　生徒会長！？　こんなタイミングに！？","ENG":"Huh?! Student President?! Right now?!","TWN":"欸欸？學生會長？！偏偏挑這種時候？！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"무슨 용무인지 묻고 싶소만.","JPN":"まず用件を聞いてもよろしいでしょうか。","ENG":"May I ask what this is about?","TWN":"敢問是何事？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그건 그러니까…","JPN":"それは……","ENG":"Well...","TWN":"就是關於…"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회 임원 후보에 관련된 사안입니다.","JPN":"生徒会役員への立候補に関してです。","ENG":"It is about the Student Council Member candidacy.","TWN":"學生會幹部候選人的事。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘…","JPN":"ナイエルさん……","ENG":"Naielle...","TWN":"奈爾…"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"굳이 이런 사소한 자리에 나이엘 양까지 동석할 필요는 없었습니다만.","JPN":"わざわざナイエルさんまで同席する必要はなかったと思いますが。","ENG":"I do not think this talk requires your presence, Naielle.","TWN":"辦公室也不大，你不需要硬跟來吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그야 나도 당연히 여기 있어야지! 차기 학생회 임원으로서 임원 후보를 논하는 자리에 빠질 수 없잖아?","JPN":"そんなことないわよ！　次期生徒会役員として役員立候補について話し合う場には参加しないといけないでしょ？","ENG":"Of course it does! How can I not be a part of a conversation when I'm the next member of the Student Council?","TWN":"我當然要跟來囉！身為下一屆的學生會幹部，要討論幹部候選人的事我怎麼可以不在？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인도 동석에 이견은 없소.","JPN":"それに関しては自分も異議はありません。","ENG":"I have no objections to her participating in this conversation.","TWN":"在下是沒意見。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"わかりました。","ENG":"Very well.","TWN":"好吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"애초에 화두를 돌리는 게 관건이었으니까요.","JPN":"そもそもこの話題を切り出すのが、目的でしたから。","ENG":"Changing the subject was what mattered in the first place.","TWN":"我本來是不想在你面前說的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 방금 뭐라고…?","JPN":"うん？　今なんて言ったの？","ENG":"Hmm? Wait, what did you just say?","TWN":"嗯？你說什麼…？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회에선 작년에 졸업한 임원의 공석을 채울 인재로서, 만장일치로 시엘 양을 추천하더군요.","JPN":"生徒会では卒業生により空席が出た役員のポストを埋める人材として、満場一致でシエルさんを推すことになりました。","ENG":"Since last year's graduation, there has been an empty seat on the Student Council. The Student Council unanimously agrees to recommend you for that seat, Ciel.","TWN":"原本的幹部在去年畢業後，幹部的位置就有空缺，因此學生會現在打算把人數補齊，而大家一致推薦希爾同學。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…에?","JPN":"……えっ？","ENG":"...Eh?","TWN":"…什麼？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"잠깐! 말도 안 돼! 그런 식으로 임원들끼리 결정하는 게 어딨어!","JPN":"ちょ、ちょっと待って！　役員だけで決めてしまうなんてないわよ！","ENG":"Wait a minute! Nonsense! What gives you guys the right to make that decision?!","TWN":"等等！怎麼可以！哪有這樣幹部自己決定的！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"물론 투표는 별개로 진행될 겁니다. 이 자릴 빌어서 학생회의 의사를 공유하는 것뿐이죠.","JPN":"もちろん全ては公正な投票によって決まります。私はただ生徒会の意向をお伝えしているだけです。","ENG":"Of course, there will be a separate vote. I just wanted to share what the Student Council's intentions were.","TWN":"當然會再找時間進行投票，我只是藉這個機會表達學生會的想法而已。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그렇지? 깜짝 놀랐네.","JPN":"そ、そうよね？　びっくりしちゃった。","ENG":"R-right? You startled me there.","TWN":"是，是吼？嚇我一跳。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래서, 시엘 양에겐 임원의 후보가 될 생각이 있는지 묻고 싶군요.","JPN":"そういうわけで、シエルさんには役員に立候補されるかどうかお聞きしたいのですが。","ENG":"So, I am asking if you would like to become a candidate for the Student Council.","TWN":"所以我是想問希爾同學，你有意願當幹部候選人嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"미안하지만 본인은 그런 직책을 맡을 수 없을 것 같소.","JPN":"申し訳ないですが、自分はそのような立場の座につくわけにはいきません。","ENG":"I am afraid I cannot take on such a position.","TWN":"抱歉，在下無法擔此重責大任。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인에겐 학업보다 중요한 일이 있고, 그것을 위해 이곳에 머물 수만은 없기 때문이오.","JPN":"自分には学校より大事な責務があり、そのために、ここに残るわけにはいかないのです。","ENG":"I cannot stay here indefinitely, for I have work that is more important than my studies.","TWN":"因為在下還有比課業更重要的事，所以無法在此久留。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"나이스…!","JPN":"よし……！","ENG":"Yes...!","TWN":"讚啦…！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…가 아니라 그게 무슨 소리야? 머물 수 없다니?","JPN":"……じゃなくて、どういうこと？","ENG":"...Wait a second, what's that supposed to mean? You can't stay?","TWN":"…沒有啦，什麼意思？為什麼不能久留？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"말 그대로요. 본인이 아카데미에 입학한 목적을 성취하고 나면, 아카데미에는 더 이상 머물 이유가 없어지는 것이지.","JPN":"言葉通りです。自分がアカデミーに入学した目的が達成されれば、それ以上ここにいる理由はありませんので。","ENG":"It is what it says. When my objective at the Academy is achieved, I have no reason to stay any longer.","TWN":"就如剛才所言，只要在下達成當初入學的目的後，自然沒有理由再繼續待在學院裡。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그 목적이란 게 대체 뭔데? 같은 학생이 목적이라고 해봐야 거기서 거길 텐데.","JPN":"その目的っていうのは何？　生徒の目的なんてそんなに大層なものじゃ……","ENG":"What do you mean by objective? Don't all students have similar goals?","TWN":"你說的目的到底是什麼？身為一個學生還能有什麼目的？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이곳에서 강자를 찾아 자웅을 겨루고, 본인을 이긴 자와 혼약을 치르는 것이오.","JPN":"ここで強者を見つけ対決し、自分に勝った者と婚約するんです。","ENG":"I must find a formidable opponent, fight, and wed whoever defeats me.","TWN":"就是在這裡找到高手跟他一較高下，若他能打贏在下，在下便要和他訂親。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"……혼약?","JPN":"……婚約？","ENG":"...Wed?","TWN":"……訂親？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"앗! 널 이긴 사람이라면… 설마?","JPN":"えっ？　あんたに勝ったのって……","ENG":"What? But the person who defeated you... is...!","TWN":"等等！你剛說他要打贏你…該不會？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"자, 잠깐만! 난 아직 그런 마음의 준비가…!","JPN":"ま、待って！　わ、私はまだ心の準備が……！","ENG":"W-wait! B-but I'm not ready for that kind of commitment...!","TWN":"先，先等一下！我還沒有心理準備要結…！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"걱정 마오. 낭자는 징표를 가지고 있지 않으니 논외라오.","JPN":"心配無用です。貴殿は「証」を持っていないので、対象外です。","ENG":"Do not worry. You do not carry the mark, so it does not include you.","TWN":"姑娘放心，你沒有信物，不在討論範圍內。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"휴우-","JPN":"よ、よかった……","ENG":"Phew...","TWN":"呼～"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 징표라는 건 뭐야? 네가 말하는 걸 가진 사람이 이 학교에 있다고?","JPN":"それで、その証っていうのは何？　それを持っている誰かがこの学校にいるってこと？","ENG":"But what's this mark you mentioned? Is there someone who has it in our school?","TWN":"那信物是什麼？學院裡有誰有嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"같은 고향에서 가르침을 얻은 동문임을 증명하는 표식이라오. 일전에 교정에서 한 차례 마주친 적이 있소.","JPN":"同じ故郷で教えを受けたことを示す表式があるのですが、以前その方と一度、校庭でお会いしました。","ENG":"A mark is a token that symbolizes one's affiliation with a sect from my hometown. I encountered him a few days before on school grounds.","TWN":"就是可以證明你師出同門的信物，不久前有在校園內遇到一個。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그 녀석하고는 겨뤄봤어?","JPN":"戦ったの？","ENG":"Did you fight him?","TWN":"你和對方打過啦？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"조만간 담판을 지을 예정이라오.","JPN":"近いうちに勝負するつもりです。","ENG":"We will soon enough.","TWN":"雙方有約好日後進行。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흐음- 결과야 뻔하네. 이 엘리트님도 제법 고전한 널 이길 수 있을 정도의 실력자라면 내가 모를 리 없잖아?","JPN":"ふーん、結果はもう見えているんじゃない？　エリートである私が苦戦したあんたに勝てる実力者なら、私が知らないわけがないし。","ENG":"Hmm... Well, then the outcome is obvious. If this person was skilled enough to beat you, someone who I had a hard time fighting, I'd know them already.","TWN":"嗯，結果很明顯，我和你交手時都陷入苦戰，對方若是能夠打贏你的高手，那我應該也認識吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그 녀석은 어떤데? 네 마음에 드는 애야?","JPN":"どういう人なの？　あんた的にはありなの？","ENG":"So, what's this person like? Do you like them?","TWN":"那傢伙怎麼樣？你喜歡嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인의 마음은 중요치 않소. 고향의 전통에 따라 본인을 이긴 강자가 반려가 될 뿐이오.","JPN":"自分の気持ちは考慮要素ではありません。故郷のしきたりに従い、自分に勝利した強者を伴侶として迎えるのみなのです。","ENG":"My preference is not of importance. It is tradition that my partner be someone stronger than me.","TWN":"在下喜歡與否不重要，而是老家的傳統便是如此，因此只要是能打贏在下的人，就是在下的伴侶。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐어? 무슨 그런 이상한 전통이 다 있어?","JPN":"はあ？　なに、その変なしきたりは？","ENG":"What? What kind of weird tradition is that?","TWN":"什麼？這是什麼詭異的傳統？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"결혼은 평생이 걸린 문제인데 자기 의사보다 중요한 게 어디 있다고.","JPN":"結婚はその後の人生がかかっているんだし、自分の意思を最も大事にすべきよ。","ENG":"Marriage is a life-changing decision. Of course your opinion matters.","TWN":"婚姻可是關係到你的一輩子欸，自己的想法當然才是最重要的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그러한 전통들이 바로 본인의 고향을 지켜온 규칙이라오.","JPN":"そのようなしきたりがあったからこそ、自分の故郷は存続してこられたのです。","ENG":"These traditions are what have brought stability to my hometown.","TWN":"這樣的傳統，正是守護在下老家的規則。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"마음에 들지 않는다는 사사로운 이유로 멋대로 행동한다면, 질서는 무너지고 말 거요.","JPN":"気に入らないという粗末な理由で勝手なマネをすると、秩序は崩壊してしまいます。","ENG":"If I fall out of line for trivial reasons, such as my preference, order will collapse.","TWN":"若是只是因為不喜歡這種私人理由便任意妄為，那秩序會瓦解的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐래.","JPN":"何言ってんの。","ENG":"Is that what you really think?","TWN":"胡說什麼。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"네가 원하지 않는 규칙이 있다면, 애초에 그 규칙을 따를 필요가 없는 거 아냐?","JPN":"あんた自身が納得していないしきたりなら、守る必要はないんじゃないの？","ENG":"If there's a rule you don't like, then isn't it better to just not follow it in the first place?","TWN":"要是你不想要那樣的規則，打從一開就不需要遵守不是嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그건…","JPN":"それは……","ENG":"That is...","TWN":"在下…"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘, 다른 사람의 사정에 지나친 간섭은 좋지 않습니다.","JPN":"ナイエルさん、他人の事情にあまり深入りすべきではありません。","ENG":"Naielle, it is bad manners to pry into other people's personal lives.","TWN":"奈爾，別人的事不適合介入太深。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"쳇-","JPN":"ちぇっ！","ENG":"Tch.","TWN":"嘖。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그럼 떠나던지 말던지 마음대로 해. 후보자가 줄어들면 나야 편하니까.","JPN":"じゃあ勝手に去れば？　候補者が減ってくれたら、私はラッキーよ。","ENG":"Then do whatever you want. Better for me if there's one less candidate to worry about.","TWN":"要走還是要留隨便你啦，反正少一個人競爭我也樂得開心。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그런데 시엘 양…? 정황상 지금까지 한 얘기들은 남들에게 함부로 발설하면 곤란한 내용처럼 들리는데요?","JPN":"ところでシエルさん……おそらく今のお話は外部の者に漏らしてはいけない内容ですよね？","ENG":"But, Ciel…? I feel that the context of what you have been telling us is rather sensitive information. Is that correct?","TWN":"不過希爾同學…你若是把剛才的話隨便說給別人聽，別人可能會無法理解。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"하긴, 입단속을 못 하는 건 본인의 큰 문제라고 사부님께서도 자주 말씀하셨소.","JPN":"たしかに、口が軽いのは自分の大きな問題点だと師匠にもよく言われていました。","ENG":"Yes, my master had also told me that it was a major issue that I could not keep my mouth shut.","TWN":"也是，師父也常說在下管不住嘴巴。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그래서 작전 중 신분을 위장할 때에도, 되도록 말을 할 필요없는 역할을 부여받곤 했지.","JPN":"だから身分を偽装して行う作戦では、できるだけ口を利く必要のない役割を任されたりしたものです。","ENG":"That is also why I was typically given non-verbal roles when I was in disguise for an operation.","TWN":"所以在作戰中需要偽裝身分時，在下通常都是負責不需要說話的角色。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"작전은 또 뭐야…? 너 군인이었어?","JPN":"作戦って何……？　あんた軍人だったの？","ENG":"Operation...? Were you a soldier?","TWN":"作戰又是怎麼回事…？你是軍人嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"대강의 전말은 이해했습니다.","JPN":"だいたいの状況は理解しました。","ENG":"I understand the overall situation.","TWN":"原因我大致都了解了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양의 뜻이 그렇다면 입후보는 강요하지 않겠어요.","JPN":"シエルさんの意思がそうなのでしたら、私も無理強いはしません。","ENG":"If that is your decision, Ciel, then I will not force you to become a candidate.","TWN":"若希爾同學的意思如此，那我也不會勉強你選幹部。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미의 문은 언제나 열려 있으니, 이곳에 오는 것도 떠나는 것도 자유이죠.","JPN":"アカデミーの扉はいつでも開いていますから、ここには来るのも去るのも自由です。","ENG":"Additionally, the Academy doors are always open. You may come and go as you please.","TWN":"學院的門永遠都開著，出入都是自由的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이해해주어서 고맙구려.","JPN":"ご理解いただき感謝します。","ENG":"Thank you for understanding.","TWN":"謝謝你的諒解。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"잠시만 기다려줄래요? 학생회실에 먹을 것이 있거든요.","JPN":"少し待っていただけますか？　生徒会室におやつがありますので。","ENG":"Could you wait here for a moment? I will bring back some food from the Student Council office.","TWN":"你等我一下，學生會辦公室裡應該有吃的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼, 염치 불고하고 신세 지리다.","JPN":"ありがとうございます。","ENG":"Then, in spite of the circumstances, I shall gladly accept.","TWN":"那在下就不客氣了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"입맛에는 맞나요?","JPN":"味はどうですか？","ENG":"Does it suit your taste?","TWN":"合你的胃口嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"맛이 좋구려. 특히 이 케이크란 것들이 마음에 든다오.","JPN":"極めて美味しいです。このケーキというもの……非常に気に入りました。","ENG":"It is delicious. I especially enjoyed this dish you call cake.","TWN":"味道很好，在下尤其喜歡這個叫作蛋糕的東西。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"웃겨. 도대체 무슨 시골에서 왔길래 케이크를 처음 먹어본대?","JPN":"呆れたわ。ケーキも知らないなんていったいどこの田舎者なの？","ENG":"That's funny. Is this your first time trying cake? Were you living under a rock or something?","TWN":"笑死，你是從鄉下來的嗎？竟然沒吃過蛋糕。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생이 주로 접하는 식재료를 이용해 익숙한 식단을 꾸리는 것 또한 학생회의 역할이죠.","JPN":"生徒に親しみのある食材を使って食事を提供するのも、我々生徒会の役割の一つです。","ENG":"It is the Student Council's duty to introduce menus with ingredients that the students are familiar with.","TWN":"利用學生經常接觸到的食材來規劃食譜也是學生會的職責。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"시엘 양은 평소에 무엇을 먹었나요?","JPN":"シエルさんは普段、どんな物を食べているんですか？","ENG":"Ciel, what do you normally eat?","TWN":"希爾同學平時都吃些什麼呢？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"곰 간이나 소 내장을 주로 먹곤 했소.","JPN":"クマの肝や、牛の内臓を主に食べていました。","ENG":"I used to eat the liver of bears or cow intestines.","TWN":"平時都吃熊肝或是牛內臟。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으엑- 그런 걸 먹고도 건강에 문제가 없는 거야?","JPN":"おえっ、そんなものを食べていて体は大丈夫なの？","ENG":"Eww...! Don't those affect your health or anything?!","TWN":"欸額，吃那種東西不會生病嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인 정도라면 건강한 편이라 생각되오만.","JPN":"自分の体はそれなりに健康だと思われます。","ENG":"I think of myself to be on the healthy side.","TWN":"在下是蠻健康的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"가능한… 구할 수 있도록 노력해보죠.","JPN":"それは……手に入れるためにできる限りのことはしてみますね。","ENG":"I will... do my best to see if I can procure them.","TWN":"我…會盡量找到這些食材。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회장, 뭔가 말이랑 다르게 편견으로 가득한 표정인데.","JPN":"生徒会長、言葉とは違って偏見でいっぱいな顏をしてるよ。","ENG":"Your words don't seem to match your prejudice-filled expression.","TWN":"學生會長，你的話和表情好像搭不起來欸？表情一臉嫌惡的樣子。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"신기하구려.","JPN":"不思議です。","ENG":"Strange.","TWN":"好奇妙。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"살아오면서 많은 타인들의 선의를 받아왔지만… 이런 느낌은 처음이오.","JPN":"これまで、様々な者から善意を向けられてきましたが……このような感覚は初めてです。","ENG":"I have been shown hospitality from many others... but this feeling is a first.","TWN":"在下活到現在接受過許多人的好意…但這種感覺還是第一次。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"선행이나 배려와는 다른 느낌… 그저 이렇게 함께 있는 것으로 기분이 이렇게 고양될 수 있다니.","JPN":"善行や気遣いとは違う何か……一緒にいるだけでここまで気分が高揚するとは。","ENG":"It is different from acts of kindness or consideration... It is strange that I feel so uplifted simply by being with others.","TWN":"不是因為別人的照顧或體貼…而是光是這樣待在一起，心情就變得很好。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"흑동의 사람은 타인의 마음을 이용할지언정 자신의 마음이 움직여선 안 된다.","JPN":"黒東の者は他人の気持ちを利用することはあっても、自分の心を動かされてはならぬ。","ENG":"As members of Black East, we may play on others' feelings, but we should not be the ones swayed.","TWN":"黑東的人寧可利用別人的好心，也不可以心裡動搖。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"마음에 휘둘리는 암살자는 쓸모 없어진다는 것을 명심하거라.","JPN":"感情に振り回されれば、暗殺者として無価値になると思え。","ENG":"A swayed assassin is useless. Keep that in mind.","TWN":"你要記住，一個心裡動搖的刺客與廢人無異。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"늦은 시간까지 신세를 졌구려. 이만 일어나보리다.","JPN":"こんな時間までご迷惑をおかけしました。そろそろ戻ります。","ENG":"I have overstayed my welcome. I should depart.","TWN":"打擾你們這麼久，現在時間已晚，在下先離開。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"피곤하다면 쉬고 가시죠. 학생회실 뒤편엔 게스트용 침실이 구비되어 있으니까요.","JPN":"お疲れなのでしたら、休んでいってください。生徒会室の裏には寝室が用意されていますから。","ENG":"If you are tired, rest before you go. There is a guest bedroom behind our office.","TWN":"你累的話休息一下再走吧，學生會辦公室後面有客房。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회실에 그런 것까지 있어?!","JPN":"生徒会室ってそんなものまであるの！？","ENG":"A guest bedroom?! What doesn't the Student Council office have?!","TWN":"學生會辦公室連客房都有喔？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…미안하오.","JPN":"……申し訳ありません。","ENG":"...I am sorry.","TWN":"…抱歉。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야? 왜 저렇게 급하대? 또 화장실인가?","JPN":"え？　何であんなに急ぐんだろう？　もしかしてまたトイレとか？","ENG":"Huh? Where's she going? Another trip to the restroom?","TWN":"她幹嘛？急什麼急？又要跑廁所喔？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};